import{_ as l,I as n,o,c as r,a6 as a,bk as s,bl as d,j as e,J as h}from"./chunks/framework.zaV2WUSU.js";const x=JSON.parse('{"title":"Getting Started","description":"","frontmatter":{"aside":false,"outline":false},"headers":[],"relativePath":"user_guide/getting_started.md","filePath":"user_guide/getting_started.md"}'),c={name:"user_guide/getting_started.md"},g={class:"info custom-block"};function u(f,t,p,y,b,m){const i=n("SerialChecker");return o(),r("div",null,[t[2]||(t[2]=a('<h1 id="getting-started" tabindex="-1">Getting Started <a class="header-anchor" href="#getting-started" aria-label="Permalink to “Getting Started”">​</a></h1><div class="tip custom-block"><p class="custom-block-title custom-block-title-default">TIP</p><p><strong>About modchipped Switch console users</strong></p><p>If you already know you have a modchipped Switch console, you can skip ahead to the <a href="./../user_guide/modchip/index">Modchip Introduction</a> page.</p></div><h2 id="finding-your-serial-number" tabindex="-1">Finding your serial number <a class="header-anchor" href="#finding-your-serial-number" aria-label="Permalink to “Finding your serial number”">​</a></h2><p>In the RCM path, we&#39;ll first determine if your Switch is vulnerable to fusee-gelee, the exploit we will be using to launch CFW.</p><p>The fusee-gelee vulnerability was discovered independently by different Switch hacking teams, who all independently released versions of the exploit in April 2018. Nintendo and NVIDIA were informed 90 days before these releases, and patched consoles were launched by mid-2018. NVIDIA <a href="https://nvidia.custhelp.com/app/answers/detail/a_id/4660/~/security-notice%3A-nvidia-tegra-rcm-vulnerability" target="_blank" rel="noreferrer">publicly acknowledged the flaw</a> in April as well. In July 2019, Nintendo announced updated consoles: the Switch Lite (HDH-001), and a new model of original Switch (HAC-001(-01)/&quot;V2&quot;) with better battery life. Both of these new models use the Tegra X1+ (also known as Mariko, the T214, and T210B01) with a brand-new bootROM, and cannot currently be hacked without a modchip.</p><p>Patched and Mariko units can be identified by their serial number. This number can be found in the Settings applet at <strong>System -&gt; Serial Information</strong>. You can also find it on the bottom of the console, adjacent to the charging port. However, it is always more accurate to use the serial reported in Settings instead, especially if you aren&#39;t the original owner of the console.</p><p><img src="'+s+'" alt="Visual for System Settings serial location"></p><p><img src="'+d+'" alt="Visual for serial location on the bottom of console"></p><h2 id="determining-if-your-switch-is-vulnerable" tabindex="-1">Determining if your Switch is vulnerable <a class="header-anchor" href="#determining-if-your-switch-is-vulnerable" aria-label="Permalink to “Determining if your Switch is vulnerable”">​</a></h2><p>The community has crowdsourced a list of known serial numbers which are vulnerable to fusee-gelee.</p>',10)),e("div",g,[t[0]||(t[0]=e("p",{class:"custom-block-title custom-block-title-default"},"INFO",-1)),t[1]||(t[1]=e("p",null,"Enter your Switch serial number to check if it's exploitable via RCM:",-1)),h(i)]),t[3]||(t[3]=a('<p>If you would rather look at a table containing serial number ranges, unfold the <code>Serial list</code> section below.</p><details class="details custom-block"><summary>Serial list</summary><p>The following information is based on <a href="https://gbatemp.net/threads/switch-informations-by-serial-number-read-the-first-post-before-asking-questions.481215/" target="_blank" rel="noreferrer">this GBATemp thread</a>.</p><table tabindex="0"><thead><tr><th style="text-align:left;">Serial Numbers</th><th style="text-align:left;"><span style="color:green;">Unpatched</span></th><th style="text-align:left;"><span style="color:orange;">Potentially patched</span></th><th style="text-align:left;"><span style="color:red;">Patched</span></th></tr></thead><tbody><tr><td style="text-align:left;">XAW1</td><td style="text-align:left;">XAW10000000000 to XAW10065000000</td><td style="text-align:left;">XAW10065000000 to XAW10120000000</td><td style="text-align:left;">XAW10120000000 and up</td></tr><tr><td style="text-align:left;">XAW4</td><td style="text-align:left;">XAW40000000000 to XAW40011000000</td><td style="text-align:left;">XAW40011000000 to XAW40012000000</td><td style="text-align:left;">XAW40012000000 and up</td></tr><tr><td style="text-align:left;">XAW7</td><td style="text-align:left;">XAW70000000000 to XAW70017500000</td><td style="text-align:left;">XAW70017500000 to XAW70030000000</td><td style="text-align:left;">XAW70030000000 and up</td></tr><tr><td style="text-align:left;">XAW9</td><td style="text-align:left;"><strong>N/A</strong></td><td style="text-align:left;">XAW90000000000 and up</td><td style="text-align:left;"><strong>N/A</strong></td></tr><tr><td style="text-align:left;">XAJ1</td><td style="text-align:left;">XAJ10000000000 to XAJ10020000000</td><td style="text-align:left;">XAJ10020000000 to XAJ10030000000</td><td style="text-align:left;">XAJ10030000000 and up</td></tr><tr><td style="text-align:left;">XAJ4</td><td style="text-align:left;">XAJ40000000000 to XAJ40044000000</td><td style="text-align:left;">XAJ40044000000 to XAJ40083000000</td><td style="text-align:left;">XAJ40083000000 and up</td></tr><tr><td style="text-align:left;">XAJ7</td><td style="text-align:left;">XAJ70000000000 to XAJ70040000000</td><td style="text-align:left;">XAJ70040000000 to XAJ70050000000</td><td style="text-align:left;">XAJ70050000000 and up</td></tr><tr><td style="text-align:left;">XAK1</td><td style="text-align:left;"><strong>N/A</strong></td><td style="text-align:left;">XAK10000000000 and up</td><td style="text-align:left;"><strong>N/A</strong></td></tr></tbody></table><p>If your serial number is not listed above, your device is not vulnerable to the fusee-gelee exploit.</p></details><h2 id="firmware-version-table" tabindex="-1">Firmware Version Table <a class="header-anchor" href="#firmware-version-table" aria-label="Permalink to “Firmware Version Table”">​</a></h2><p>The table below shows firmware version information regarding the available exploits based on the firmware version your Switch is on. Any firmware version past <code>4.1.0</code> is not vulnerable to software exploits.</p><ul><li><strong>RCM</strong> means your Switch is vulnerable to the fusee-gelee exploit in RCM.</li><li><strong>Caffeine</strong> is an old software exploit that works with firmware version <code>4.1.0</code>.</li><li><strong>Modchip</strong> means you need to have a modchipped Switch.</li></ul><table tabindex="0"><thead><tr><th style="text-align:left;">System Version</th><th style="text-align:left;">Unpatched Switch Systems</th><th style="text-align:left;">Patched or Mariko Switch Systems</th></tr></thead><tbody><tr><td style="text-align:left;">1.0.0 - 4.0.1</td><td style="text-align:left;"><a href="./rcm/index"><strong>RCM</strong></a></td><td style="text-align:left;"><strong>N/A</strong></td></tr><tr><td style="text-align:left;">4.1.0</td><td style="text-align:left;"><a href="./rcm/index"><strong>RCM</strong></a></td><td style="text-align:left;">Caffeine</td></tr><tr><td style="text-align:left;">5.0.0+</td><td style="text-align:left;"><a href="./rcm/index"><strong>RCM</strong></a></td><td style="text-align:left;"><a href="./modchip/index"><strong>Modchip</strong></a></td></tr></tbody></table><h2 id="continue-with-the-right-path-for-your-switch" tabindex="-1">Continue with the right path for your Switch <a class="header-anchor" href="#continue-with-the-right-path-for-your-switch" aria-label="Permalink to “Continue with the right path for your Switch”">​</a></h2><div class="cards"><div class="card"><p><strong>If your Switch is not patched, click the button below to follow the RCM path of the guide.</strong></p><p><a href="rcm/index" class="btn btn-solid">Continue to RCM →</a></p></div><div class="card"><p><strong>If your Switch is patched and modchipped, click the button below to follow the Modchip path of the guide.</strong></p><p><a href="modchip/index" class="btn btn-solid">Continue to Modchip introduction →</a></p></div></div><details class="details custom-block"><summary>Frequently Asked Questions about this page</summary><ul><li><p><strong>Q: How reliable is the crowdsourced list of vulnerable serial numbers, and what if my serial number is not listed?</strong></p><p>A: To our knowledge, there hasn&#39;t been a single console which has disproved the trends documented here. Unless your serial is potentially patched, you can be certain that the table is accurate to reality.</p></li></ul></details>',9))])}const A=l(c,[["render",u]]);export{x as __pageData,A as default};
